import React, { useRef, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import "../style/NeuralNetwork3D.css";

/* ── Node data (3-layer network) ── */
const NODES = [
  // Input layer — x = -2.2
  { id: 0, label: "Python",      pos: [-2.2,  1.5,  0.1], color: "#4A90D9", r: 0.1  },
  { id: 1, label: "PostgreSQL",  pos: [-2.2,  0.5,  0.2], color: "#336791", r: 0.09 },
  { id: 2, label: "FastAPI",     pos: [-2.2, -0.5, -0.1], color: "#009688", r: 0.09 },
  { id: 3, label: "pandas",      pos: [-2.2, -1.5,  0.1], color: "#E77C2C", r: 0.08 },
  // Processing layer — x = 0
  { id: 4, label: "Pipeline",    pos: [ 0,    1.3,  0.3], color: "#C49A7A", r: 0.12 },
  { id: 5, label: "API Layer",   pos: [ 0,    0.2, -0.4], color: "#D4A574", r: 0.11 },
  { id: 6, label: "ML Engine",   pos: [ 0,   -0.7,  0.5], color: "#B4846C", r: 0.12 },
  { id: 7, label: "Scheduler",   pos: [ 0,   -1.6, -0.2], color: "#C49A7A", r: 0.09 },
  // Output layer — x = 2.2
  { id: 8, label: "KPI",         pos: [ 2.2,  1.0,  0.1], color: "#22C55E", r: 0.11 },
  { id: 9, label: "Predict",     pos: [ 2.2,  0,   -0.1], color: "#22C55E", r: 0.1  },
  { id: 10, label: "Reports",    pos: [ 2.2, -1.0,  0.1], color: "#22C55E", r: 0.1  },
];

const EDGES = [
  // Input → Processing
  [0, 4], [0, 5], [0, 6],
  [1, 4], [1, 5],
  [2, 5],
  [3, 4], [3, 6], [3, 7],
  // Processing → Output
  [4, 8], [4, 10],
  [5, 8], [5, 9],
  [6, 9],
  [7, 8], [7, 10],
];

/* ── Pulsing node sphere ── */
function Node({ id, pos, color, r }) {
  const ref = useRef();
  const phase = useRef(Math.random() * Math.PI * 2);
  useFrame(({ clock }) => {
    if (!ref.current) return;
    const pulse = 1 + Math.sin(clock.elapsedTime * 1.8 + phase.current) * 0.12;
    ref.current.scale.setScalar(pulse);
  });
  return (
    <mesh ref={ref} position={pos}>
      <sphereGeometry args={[r, 14, 14]} />
      <meshBasicMaterial color={color} transparent opacity={0.85} />
    </mesh>
  );
}

/* ── Animated edge line ── */
function Edge({ from, to, idx }) {
  const phase = useRef(Math.random() * Math.PI * 2);
  const obj = useMemo(() => {
    const pFrom = new THREE.Vector3(...from.pos);
    const pTo   = new THREE.Vector3(...to.pos);
    const geo   = new THREE.BufferGeometry().setFromPoints([pFrom, pTo]);
    const mat   = new THREE.LineBasicMaterial({
      color: "#C49A7A",
      transparent: true,
      opacity: 0.25,
    });
    return new THREE.Line(geo, mat);
  }, [from, to]);

  useFrame(({ clock }) => {
    if (!obj.material) return;
    obj.material.opacity = 0.15 + Math.sin(clock.elapsedTime * 1.2 + phase.current) * 0.12;
  });

  return <primitive object={obj} />;
}

/* ── Floating background particles ── */
function BgParticles() {
  const geo = useMemo(() => {
    const COUNT = 250;
    const pos = new Float32Array(COUNT * 3);
    for (let i = 0; i < COUNT; i++) {
      pos[i * 3]     = (Math.random() - 0.5) * 8;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 5;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 4 - 1;
    }
    const g = new THREE.BufferGeometry();
    g.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    return g;
  }, []);
  return (
    <points geometry={geo}>
      <pointsMaterial color="#C49A7A" size={0.018} transparent opacity={0.2} sizeAttenuation />
    </points>
  );
}

/* ── Full scene ── */
function NetworkScene() {
  const groupRef = useRef();
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    groupRef.current.rotation.y = Math.sin(clock.elapsedTime * 0.15) * 0.3;
    groupRef.current.rotation.x = Math.sin(clock.elapsedTime * 0.1) * 0.08;
  });

  return (
    <group ref={groupRef}>
      <BgParticles />
      {EDGES.map(([a, b], i) => (
        <Edge key={i} idx={i} from={NODES[a]} to={NODES[b]} />
      ))}
      {NODES.map((n) => (
        <Node key={n.id} {...n} />
      ))}
    </group>
  );
}

const NeuralNetwork3D = () => (
  <div className="nn3d-wrap">
    <div className="nn3d-canvas" aria-hidden="true">
      <Canvas camera={{ position: [0, 0, 5.5], fov: 50 }}>
        <NetworkScene />
      </Canvas>
    </div>
    <div className="nn3d-legend">
      <div className="nn3d-legend-group">
        <span className="nn3d-dot" style={{ background: "#4A90D9" }} />Input
      </div>
      <div className="nn3d-legend-group">
        <span className="nn3d-dot" style={{ background: "#C49A7A" }} />Processing
      </div>
      <div className="nn3d-legend-group">
        <span className="nn3d-dot" style={{ background: "#22C55E" }} />Output
      </div>
    </div>
  </div>
);

export default NeuralNetwork3D;
